sources.frameParserCode:
function parse(frame) {
  const bytes = [];
  for (let i = 0; i < frame.length; i += 2) {
    const byte = parseInt(frame.slice(i, i + 2), 16);
    if (!Number.isNaN(byte)) bytes.push(byte);
  }

  const readSigned24BE = (offset) => {
    if (offset < 0 || offset + 2 >= bytes.length) return NaN;
    let value = ((bytes[offset] || 0) << 16) | ((bytes[offset + 1] || 0) << 8) | (bytes[offset + 2] || 0);
    if (value & 0x800000) value -= 0x1000000;
    return value;
  };
  const ads24ToVoltage = (raw) => (raw * 2.5) / 8388608.0;
  const voltageToStrain = (voltage) => (4 * voltage) / (100 * 2 * 2.5);
  const rawToStrain = (raw) => voltageToStrain(ads24ToVoltage(raw));
  const ads124S08CodeToTemperature = (code) => {
    const A = 3.9083e-3;
    const B = -5.775e-7;
    const scale = 2.980232e-6;
    const discriminant = (A * A) - (4 * B * (1 - (code * scale)));
    if (discriminant < 0) return NaN;
    return (-A + Math.sqrt(discriminant)) / (2 * B);
  };
  const readSeries = (offset, count) => {
    const values = [];
    for (let i = 0; i < count; i++) values.push(rawToStrain(readSigned24BE(offset + i * 3)));
    return values;
  };

  // Compact frame observed on 2026-06-18:
  // content length = 1336 bytes, 5-byte inner header, 4 channels * 110 samples * int24 BE, 11-byte tail.
  const compactHeaderLength = 5;
  const compactTailLength = 11;
  const compactChannelCount = 4;
  const compactDataLength = bytes.length - compactHeaderLength - compactTailLength;
  if (compactDataLength > 0 && compactDataLength % (compactChannelCount * 3) === 0) {
    const compactSamples = compactDataLength / (compactChannelCount * 3);
    if (compactSamples > 0) {
      const channelOffset = (channel) => compactHeaderLength + channel * compactSamples * 3;
      const strain1 = readSeries(channelOffset(0), compactSamples);
      const strain2 = readSeries(channelOffset(1), compactSamples);
      const strain3 = readSeries(channelOffset(2), compactSamples);
      return {
        title: 'STM32 Bearing Data V2',
        datasets: [
          { index: 0, title: 'Strain 1', value: strain1[strain1.length - 1], buffer: strain1 },
          { index: 1, title: 'Strain 2', value: strain2[strain2.length - 1], buffer: strain2 },
          { index: 2, title: 'Strain 3', value: strain3[strain3.length - 1], buffer: strain3 }
        ]
      };
    }
  }

  // Original V2 frame: 3 channels * 160 samples plus one ADS124S08 temperature code.
  const strainSamples = 160;
  const strain1Offset = 10;
  const strain2Offset = 490;
  const strain3Offset = 970;
  const tempOffset = 1450;

  if (bytes.length < tempOffset + 3) return [];

  const strain1 = readSeries(strain1Offset, strainSamples);
  const strain2 = readSeries(strain2Offset, strainSamples);
  const strain3 = readSeries(strain3Offset, strainSamples);
  const temperature = ads124S08CodeToTemperature(readSigned24BE(tempOffset));

  return {
    title: 'STM32 Bearing Data V2',
    datasets: [
      { index: 0, title: 'Strain 1', value: strain1[strain1.length - 1], buffer: strain1 },
      { index: 1, title: 'Strain 2', value: strain2[strain2.length - 1], buffer: strain2 },
      { index: 2, title: 'Strain 3', value: strain3[strain3.length - 1], buffer: strain3 },
      { index: 3, title: 'Temperature', value: temperature }
    ]
  };
}

